def is_prime(n):
    """Check if a number is prime."""
    if n <= 1:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

def sum_of_digits(n):
    """Return the sum of the digits of a number."""
    return sum(int(digit) for digit in str(n))

def skjkasdkd(lst):
    """Find the largest prime number in the list and return the sum of its digits."""
    largest_prime = -1

    for num in lst:
        if is_prime(num) and num > largest_prime:
            largest_prime = num

    if largest_prime == -1:
        return 0  # No prime found, return 0 or appropriate value

    return sum_of_digits(largest_prime)

# Example usage:
print(skjkasdkd([0, 3, 2, 1, 3, 5, 7, 4, 5, 5, 5, 2, 181, 32, 4, 32, 3, 2, 32, 324, 4, 3]))  # Output: 10
print(skjkasdkd([1, 0, 1, 8, 2, 4597, 2, 1, 3, 40, 1, 2, 1, 2, 4, 2, 5, 1]))  # Output: 25
print(skjkasdkd([1, 3, 1, 32, 5107, 34, 83278, 109, 163, 23, 2323, 32, 30, 1, 9, 3]))  # Output: 13
print(skjkasdkd([0, 724, 32, 71, 99, 32, 6, 0, 5, 91, 83, 0, 5, 6]))  # Output: 11
print(skjkasdkd([0, 81, 12, 3, 1, 21]))  # Output: 3
print(skjkasdkd([0, 8, 1, 2, 1, 7]))  # Output: 7
```

### Explanation:
1. **is_prime(n)**: This helper function checks if a number `n` is prime by testing divisibility from 2 up to the square root of `n`.
2. **sum_of_digits(n)**: This helper function computes the sum of the digits of the number `n`.
3. **skjkasdkd(lst)**: This function iterates through the list `lst`, finds the largest prime number, and returns the sum of its digits. If no prime is found, it returns 0.

